log_queries.query:
{
  auditEvents(first: 100, filterBy: {
    action: ["context.secret.accessed", "workflow.job.started"],
    scope: "project",
    startTime: "2024-01-01T00:00:00Z"
  }) {
    edges {
      node {
        action
        actor
        timestamp
        metadata {
          ... on ContextSecretAccessedMetadata {
            contextName
            secretName
          }
          ... on WorkflowJobStartedMetadata {
            workflowName
            isFromFork
          }
        }
      }
    }
  }
}
